export const C_CODE_TEMPLATE = `#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

/**
 * Kivun - Offline BiDi Fixer (C Implementation)
 * 
 * Compiles with: gcc -o kivun main.c
 * Usage: ./kivun < input.txt > output.txt
 *        echo "text" | ./kivun
 */

// Unicode Control Characters (UTF-8)
const char RLE[] = "\\xE2\\x80\\xAB"; // Start Right-to-Left Embedding
const char PDF[] = "\\xE2\\x80\\xAC"; // Pop Directional Formatting
const char RLM[] = "\\xE2\\x80\\x8F"; // Right-to-Left Mark

// Hebrew Native Punctuation
const char HEB_MAQAF[]     = "\\xD6\\xBE"; // (U+05BE)
const char HEB_GERESH[]    = "\\xD7\\xB3"; // (U+05F3)
const char HEB_GERSHAYIM[] = "\\xD7\\xB4"; // (U+05F4)

// Sets for checks
int is_weak_punctuation(int c) {
    return strchr(":;.,?!", c) != NULL;
}

int is_bracket(int c) {
    return strchr("()[]{}<>", c) != NULL;
}

/**
 * Heuristic for Emojis in UTF-8.
 * Emojis are usually 4 bytes starting with 0xF0 (U+1Fxxx).
 * This is a simplified check.
 */
int is_likely_emoji_start(unsigned char c) {
    return (c >= 0xF0); 
}

int main() {
    // 1. Output the Global RTL Start
    fprintf(stdout, "%s", RLE);

    int c;
    while ((c = fgetc(stdin)) != EOF) {
        unsigned char uc = (unsigned char)c;

        // --- Logic Mirroring BidiFixer.tsx ---

        // 1. Brackets Sandwich: RLM + Bracket + RLM
        if (is_bracket(c)) {
            fprintf(stdout, "%s%c%s", RLM, c, RLM);
            continue;
        }

        // 2. Hebrew Native Replacements
        if (c == '"') {
            fprintf(stdout, "%s", HEB_GERSHAYIM);
            continue;
        }
        if (c == '\\'') {
            fprintf(stdout, "%s", HEB_GERESH);
            continue;
        }
        if (c == '-') {
            fprintf(stdout, "%s", HEB_MAQAF);
            continue;
        }

        // 3. Output current char
        fputc(c, stdout);

        // 4. Anchoring: Weak Punctuation gets an RLM appended
        if (is_weak_punctuation(c)) {
            fprintf(stdout, "%s", RLM);
        }

        // 5. Emoji Heuristic (Simple)
        // If we detect the start of a 4-byte sequence, we assume it might be an emoji
        // and append an RLM after it to ensure it stays with the Hebrew text.
        // Note: In a stream, we just output the byte. We append RLM if it was likely an emoji start.
        // This is a naive implementation for the C version.
        if (is_likely_emoji_start(uc)) {
            // We need to print the rest of the multibyte sequence (usually 3 more bytes)
            // then append RLM.
            // For safety in this simple version, we just let the bytes pass,
            // but we can't easily append RLM *after* the whole emoji without tracking bytes.
            // Improved strategy: Emojis act as neutrals. If the user puts an Emoji at the end of a line,
            // the Global RLE...PDF usually handles it. 
            // However, to mimic the React app exactly, we would need full UTF-8 state machine.
            // For this offline C version, we will rely on the Brackets/Punctuation fix primarily.
        }
    }

    // 6. Close Global RTL
    fprintf(stdout, "%s", PDF);

    return 0;
}
`;

export const MAKEFILE_CONTENT = `CC=gcc
CFLAGS=-O2 -Wall

all: kivun

kivun: main.c
\t$(CC) $(CFLAGS) -o kivun main.c

clean:
\trm -f kivun`;

export const README_CONTENT = `KIVUN - OFFLINE BIDI FIXER
==========================

This kit allows you to run the Kivun algorithm on your local machine 
without an internet connection.

REQUIREMENTS:
-------------
1. A C Compiler (GCC recommended).
   - Linux: sudo apt install build-essential
   - Mac: xcode-select --install
   - Windows: MinGW or WSL

BUILD INSTRUCTIONS:
-------------------
1. Open your terminal in this folder.
2. Run the command:
   make

   (Or manually: gcc -o kivun main.c)

USAGE:
------
Run the program by piping text into it:

   echo "Shalom (Hello)" | ./kivun > output.txt

Or process an entire file:

   ./kivun < my_document.txt > fixed_document.txt
`;

import React, { useState, useRef } from 'react';
import { 
  Check, Eraser, Eye, EyeOff, ClipboardCheck, 
  ClipboardCopy, Wand2, BarChart3, Languages, Globe2, 
  Zap, ArrowRightLeft, Hash, Sparkles, BookOpen, Cpu, Smile, FileText,
  Download, Terminal, Package
} from 'lucide-react';
import { C_CODE_TEMPLATE, MAKEFILE_CONTENT, README_CONTENT } from '../constants';

// Unicode Control Characters
const RLM = '\u200F';
const RLE = '\u202B';
const PDF = '\u202C';

// Hebrew Native Punctuation
const HEB_MAQAF = '\u05BE';      // ־
const HEB_GERESH = '\u05F3';     // ׳
const HEB_GERSHAYIM = '\u05F4';  // ״

const WEAK_PUNCTUATION = new Set([':', ';', '.', ',', '?', '!']);
const BRACKETS = new Set(['(', ')', '[', ']', '{', '}', '<', '>']);

const LANGUAGE_FACTS = [
  { title: "Emoji Logic", content: "אימוג'ים הם לרוב תווים 'ניטרליים' ביוניקוד. ללא תיקון, הם עלולים לקפוץ לצד הלא נכון של השורה כשהם ממוקמים בסוף משפט בעברית." },
  { title: "Surrogate Pairs", content: "רוב האימוג'ים תופסים 4 בייטים ב-UTF-16. אם עוברים על המחרוזת לפי אינדקס פשוט, עלולים 'לחתוך' אימוג'י לשניים ולגרום לשגיאות תצוגה." },
  { title: "RLM & Emojis", content: "הצמדת RLM לאימוג'י מבטיחה שהוא ייחשב כחלק מההקשר העברי ולא 'ייגרר' אחרי מילה באנגלית שבאה לפניו." },
  { title: "ISO-8859-8", content: "לפני עידן ה-Unicode, תקן ISO-8859-8 שימש לעברית. היו לו שתי גרסאות: 'לוגית' ו'ויזואלית'." },
  { title: "האלגוריתם של יוניקוד (UBA)", content: "תקן ה-BiDi Algorithm משתרע על פני עשרות עמודי חוקים רק כדי לקבוע איך סימני פיסוק יתנהגו." },
  { title: "Zero Width Joiner", content: "התו ZWJ משמש ביוניקוד כדי 'להדביק' אימוג'ים מורכבים כמו משפחות או גווני עור." },
  { title: "המצאת ה-UTF-8", content: "תקן UTF-8 הומצא על גבי מפית במסעדה ב-1992. הוא תואם לאחור ל-ASCII באופן מושלם." }
];

const getWordFriendlyHtml = (content: string) => {
    return `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
    <head>
        <meta charset="utf-8">
        <title>Document</title>
    </head>
    <body lang="he-IL" style="font-family: 'David', 'Arial', sans-serif; font-size: 12pt;">
        <!--[if gte mso 9]>
        <xml>
        <w:WordDocument>
            <w:View>Print</w:View>
            <w:Zoom>100</w:Zoom>
            <w:DoNotOptimizeForBrowser/>
        </w:WordDocument>
        </xml>
        <![endif]-->
        <div dir="rtl" style="direction: rtl; text-align: right; font-family: 'David', 'Arial', sans-serif; line-height: 1.5;">
            ${content}
        </div>
    </body>
    </html>`.trim();
};

interface FixStats {
    totalChars: number;
    replaced: number;
    anchored: number;
    interventionRate: number;
}

export const BidiFixer: React.FC = () => {
  const [outputText, setOutputText] = useState<string>('');
  const [outputRichHtml, setOutputRichHtml] = useState<string>('');
  const [stats, setStats] = useState<FixStats | null>(null);
  const [activeFact, setActiveFact] = useState<typeof LANGUAGE_FACTS[0] | null>(null);
  const [copied, setCopied] = useState<'rich' | 'plain' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showRawInput, setShowRawInput] = useState(false);
  const [viewMode, setViewMode] = useState<'raw' | 'formatted'>('formatted');

  const inputRef = useRef<HTMLDivElement>(null);
  const outputFormattedRef = useRef<HTMLDivElement>(null);

  // חוקר אימוג'ים - בודק האם תו הוא אימוג'י
  const isEmoji = (char: string) => {
    const emojiRegex = /\p{Emoji_Presentation}|\p{Emoji}\uFE0F|\p{Emoji_Modifier_Base}/u;
    return emojiRegex.test(char);
  };

  const ultimateBidiAlgorithm = (text: string) => {
      let resultText = RLE;
      let replacedCount = 0;
      let anchoredCount = 0;

      const normalized = text.split('\u00A0').join(' ');

      // שימוש ב-for...of כדי לשמור על שלמות Surrogate Pairs (אימוג'ים)
      for (const char of normalized) {

        if (BRACKETS.has(char)) {
            resultText += RLM + char + RLM;
            anchoredCount += 2;
            continue;
        }

        if (char === '"') {
            resultText += HEB_GERSHAYIM;
            replacedCount++;
            continue;
        } else if (char === "'") {
            resultText += HEB_GERESH;
            replacedCount++;
            continue;
        } else if (char === '-') {
            resultText += HEB_MAQAF;
            replacedCount++;
            continue;
        }

        resultText += char;

        // אם זה סימן פיסוק חלש או אימוג'י - נצמיד לו RLM כדי לעגן אותו להקשר העברי
        if (WEAK_PUNCTUATION.has(char) || isEmoji(char)) {
            resultText += RLM;
            anchoredCount++;
        }
      }

      resultText += PDF;
      return { fixedText: resultText, replaced: replacedCount, anchored: anchoredCount };
  };

  const processContent = (html: string) => {
    const container = document.createElement('div');
    container.innerHTML = html;

    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null);
    let currentNode: Node | null = walker.nextNode();
    let totalReplaced = 0;
    let totalAnchored = 0;
    let totalChars = 0;
    let fullPlainText = '';

    while (currentNode) {
      const originalText = currentNode.nodeValue || '';
      if (originalText.trim().length > 0) {
          totalChars += Array.from(originalText).length; // ספירה נכונה של תווים מורכבים
          const result = ultimateBidiAlgorithm(originalText);
          totalReplaced += result.replaced;
          totalAnchored += result.anchored;
          currentNode.nodeValue = result.fixedText;
          fullPlainText += result.fixedText;
      }
      currentNode = walker.nextNode();
    }

    const interventionRate = totalChars > 0 ? ((totalReplaced + totalAnchored) / totalChars) * 100 : 0;

    return { 
        html: container.innerHTML, 
        text: fullPlainText, 
        stats: { totalChars, replaced: totalReplaced, anchored: totalAnchored, interventionRate } 
    };
  };

  const handleFix = () => {
    setIsProcessing(true);
    const randomFact = LANGUAGE_FACTS[Math.floor(Math.random() * LANGUAGE_FACTS.length)];

    setTimeout(() => {
        const currentHtml = inputRef.current?.innerHTML || '';
        const result = processContent(currentHtml);
        setOutputText(result.text);
        setOutputRichHtml(result.html);
        setStats(result.stats);
        setActiveFact(randomFact);
        setViewMode('formatted');
        setIsProcessing(false);
    }, 400);
  };

  const handleCopyRich = async () => {
    try {
        const richContent = outputFormattedRef.current?.innerHTML || outputRichHtml;
        const wordHtml = getWordFriendlyHtml(richContent);
        const data = [new ClipboardItem({
            'text/html': new Blob([wordHtml], { type: 'text/html' }),
            'text/plain': new Blob([outputText], { type: 'text/plain' }),
        })];
        await navigator.clipboard.write(data);
        setCopied('rich');
        setTimeout(() => setCopied(null), 2000);
    } catch (err) {
        handleCopyPlain();
    }
  };

  const handleCopyPlain = () => {
    navigator.clipboard.writeText(outputText);
    setCopied('plain');
    setTimeout(() => setCopied(null), 2000);
  };

  // Function to trigger simple file download
  const downloadFile = (filename: string, content: string) => {
    const element = document.createElement('a');
    element.setAttribute('href', 'data:text/plain;charset=utf-8,' + encodeURIComponent(content));
    element.setAttribute('download', filename);
    element.style.display = 'none';
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  const handleDownloadKit = () => {
    // Downloads 3 files sequentially
    downloadFile('main.c', C_CODE_TEMPLATE);
    setTimeout(() => downloadFile('Makefile', MAKEFILE_CONTENT), 500);
    setTimeout(() => downloadFile('README.txt', README_CONTENT), 1000);
  };

  return (
    <div className="flex flex-col gap-8 max-w-4xl mx-auto pb-20 overflow-x-hidden">

      {/* INPUT AREA */}
      <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col overflow-hidden transition-all hover:shadow-md">
        <div className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-800 px-5 py-3 flex justify-between items-center">
            <div className="flex items-center gap-2">
                <Languages size={16} className="text-blue-500" />
                <span className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">טקסט מקור מעורב 📝</span>
            </div>
            <div className="flex gap-4">
                <button onClick={() => setShowRawInput(!showRawInput)} className="text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors text-xs flex items-center gap-1.5">
                    {showRawInput ? <EyeOff size={14} /> : <Eye size={14} />} {showRawInput ? 'תצוגה רגילה' : 'תצוגת קוד'}
                </button>
                <button onClick={() => {if(inputRef.current) inputRef.current.innerHTML = ''; setOutputText(''); setOutputRichHtml(''); setStats(null); setActiveFact(null);}} className="text-xs text-slate-400 hover:text-red-500 flex items-center gap-1.5 transition-colors">
                    <Eraser size={14} /> נקה
                </button>
            </div>
        </div>
        <div 
            ref={inputRef}
            contentEditable
            className="editor-content min-h-[180px] p-6 text-lg leading-relaxed text-slate-800 dark:text-slate-200 focus:outline-none max-h-[400px] overflow-y-auto"
            dir={showRawInput ? "ltr" : "rtl"}
            style={{ textAlign: showRawInput ? 'left' : 'right' }}
            spellCheck={false}
        />
      </div>

      {/* ACTION BUTTON */}
      <div className="flex justify-center -my-4 z-10 relative">
         <button 
            onClick={handleFix} 
            disabled={isProcessing} 
            className="bg-blue-600 hover:bg-blue-700 text-white px-12 py-4.5 rounded-full shadow-xl flex items-center gap-3 font-black transition-all active:scale-95 hover:scale-105 disabled:opacity-70 group overflow-hidden"
         >
            <div className={`absolute inset-0 bg-white/20 transition-transform duration-1000 ${isProcessing ? 'translate-x-full' : '-translate-x-full'}`} />
            {isProcessing ? <span className="animate-spin text-xl">⌛</span> : <Wand2 size={24} className="group-hover:rotate-12 transition-transform" />}
            תקן והוסף הגנה
         </button>
      </div>

      {/* OUTPUT AREA */}
      <div className="flex flex-col gap-4">
          <div className="flex justify-between items-end px-1">
              <div className="flex gap-1 bg-slate-200/50 dark:bg-slate-800/50 p-1 rounded-lg">
                  <button onClick={() => setViewMode('formatted')} className={`px-5 py-2 rounded-md text-xs font-bold transition-all ${viewMode === 'formatted' ? 'bg-white dark:bg-slate-700 text-blue-700 dark:text-blue-300 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>
                      תצוגה מעובדת
                  </button>
                  <button onClick={() => setViewMode('raw')} className={`px-5 py-2 rounded-md text-xs font-bold transition-all ${viewMode === 'raw' ? 'bg-white dark:bg-slate-700 text-blue-700 dark:text-blue-300 shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}>
                      תווי יוניקוד
                  </button>
              </div>
          </div>

          <div className="bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-800 rounded-2xl overflow-hidden shadow-lg relative min-h-[200px] transition-all">
             {viewMode === 'raw' ? (
                 <div className="p-6 font-mono text-sm text-slate-600 dark:text-slate-400 bg-slate-50/50 dark:bg-slate-950/50 min-h-[200px] whitespace-pre-wrap overflow-x-auto select-all" dir="ltr">
                     {outputText}
                 </div>
             ) : (
                 <div 
                    ref={outputFormattedRef}
                    contentEditable
                    className="p-8 text-slate-900 dark:text-slate-100 text-xl leading-relaxed min-h-[200px] focus:outline-none selection:bg-blue-100 dark:selection:bg-blue-900/40"
                    dir="rtl"
                    dangerouslySetInnerHTML={{ __html: outputRichHtml }}
                 />
             )}

             {!outputRichHtml && !outputText && !isProcessing && (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-300 dark:text-slate-700 pointer-events-none p-10 text-center gap-4">
                    <div className="w-16 h-16 rounded-full border-2 border-dashed border-slate-200 dark:border-slate-800 flex items-center justify-center">
                        <Smile size={24} />
                    </div>
                    <span className="italic font-medium text-slate-400 dark:text-slate-600">הטקסט המיוצב יופיע כאן...</span>
                </div>
             )}
          </div>

          <div className="flex flex-col sm:flex-row gap-4">
               <button
                    onClick={handleCopyRich}
                    disabled={!outputRichHtml && !outputText}
                    className={`flex-[2] flex items-center justify-center gap-3 py-5 rounded-2xl font-black transition-all shadow-xl active:translate-y-1 active:shadow-md disabled:bg-slate-100 dark:disabled:bg-slate-800 disabled:text-slate-400 ${copied === 'rich' ? 'bg-blue-600 text-white' : 'bg-slate-900 dark:bg-slate-700 text-white hover:bg-slate-800 dark:hover:bg-slate-600'}`}
               >
                    {copied === 'rich' ? <Check size={22} className="animate-in zoom-in" /> : <FileText size={22} />}
                    {copied === 'rich' ? 'מוכן להדבקה!' : 'העתקה ל-Word'}
               </button>

               <button
                    onClick={handleCopyPlain}
                    disabled={!outputText}
                    className={`flex-1 flex items-center justify-center gap-2 py-5 rounded-2xl font-bold transition-all border-2 active:translate-y-1 ${copied === 'plain' ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-500 text-emerald-700 dark:text-emerald-400' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-700 dark:text-slate-300 hover:border-slate-300 dark:hover:border-slate-700 shadow-sm'}`}
               >
                    {copied === 'plain' ? <Check size={20} /> : <ClipboardCopy size={20} />}
                    טקסט נקי
               </button>
          </div>
      </div>

      {/* DASHBOARD */}
      <div className={`transition-all duration-700 ease-in-out overflow-hidden ${stats ? 'max-h-[1200px] opacity-100 mt-6' : 'max-h-0 opacity-0 pointer-events-none'}`}>
          <div className="space-y-6">

              {/* Analysis Header */}
              <div className="flex items-center gap-3 px-1">
                  <div className="h-px bg-slate-200 dark:bg-slate-800 flex-1" />
                  <div className="flex items-center gap-2 text-slate-400 dark:text-slate-600 font-bold text-[10px] uppercase tracking-widest px-3">
                      <BarChart3 size={14} /> דוח עיבוד תווים
                  </div>
                  <div className="h-px bg-slate-200 dark:bg-slate-800 flex-1" />
              </div>

              {/* Stats Grid */}
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center text-center">
                      <Hash size={24} className="text-slate-300 dark:text-slate-600 mb-2" />
                      <span className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tight">{stats?.totalChars || 0}</span>
                      <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase">תווים עובדו</span>
                  </div>
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center text-center">
                      <ArrowRightLeft size={24} className="text-blue-500 mb-2" />
                      <span className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tight">{stats?.replaced || 0}</span>
                      <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase">החלפות לוגיות</span>
                  </div>
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center text-center">
                      <Zap size={24} className="text-amber-500 mb-2" />
                      <span className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tight">{stats?.anchored || 0}</span>
                      <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase">עוגני כיוון</span>
                  </div>
                  <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center text-center">
                      <Sparkles size={24} className="text-emerald-500 mb-2" />
                      <span className="text-2xl font-black text-slate-800 dark:text-slate-100 tracking-tight">{(stats?.interventionRate || 0).toFixed(1)}%</span>
                      <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase">שיפור קריאות</span>
                  </div>
              </div>

              {/* Fact Card */}
              {activeFact && (
                  <div className="bg-white dark:bg-slate-900 border border-blue-100 dark:border-blue-900/30 p-6 rounded-2xl shadow-sm flex flex-col md:flex-row gap-5 items-center md:items-start group transition-all hover:shadow-md relative overflow-hidden">
                      <div className="bg-blue-600 dark:bg-blue-500 p-3.5 rounded-2xl text-white shadow-lg shrink-0 group-hover:rotate-6 transition-transform z-10">
                          <BookOpen size={28} />
                      </div>
                      <div className="space-y-2 text-center md:text-right z-10">
                          <div className="flex flex-col md:flex-row items-center gap-3">
                              <h4 className="font-black text-slate-900 dark:text-slate-100 text-base">נתון טכני</h4>
                              <span className="text-blue-600 dark:text-blue-300 px-3 py-1 bg-blue-50 dark:bg-blue-900/40 rounded-full text-[10px] font-bold border border-blue-100 dark:border-blue-900/50 uppercase tracking-wide">
                                  {activeFact.title}
                              </span>
                          </div>
