                              {activeFact.content}
                          </p>
                      </div>
                      <div className="absolute -left-4 -bottom-4 opacity-[0.03] dark:opacity-[0.05] rotate-12 pointer-events-none">
                        <Globe2 size={120} className="dark:text-white" />
