// High-Fidelity Word Export Wrapper
const getWordFriendlyHtml = (content: string) => {
    return `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
    <head>
        <meta charset="utf-8">
        <title>Document</title>
        <style>
            /* Default RTL Body Style */
            body { 
                font-family: 'David', 'Arial', sans-serif; 
                font-size: 12pt; 
                direction: rtl; 
                text-align: right;
            }

            /* High-Quality List Handling for Word */
            ul, ol {
                margin-top: 0;
                margin-bottom: 0;
                direction: rtl;
                unicode-bidi: embed;
            }

            /* Ensure bullets/numbers stay on the right side */
            li {
                direction: rtl;
                text-align: right;
                margin-right: 24pt; /* Indent for bullet */
                mso-list-l-id: 1; /* Help Word identify lists */
            }

