export interface GlobalStatsData {
  totalCharsAllTime: number;
  totalCharsMonth: number;
  totalCharsWeek: number;
  totalReplacements: number;
  usageCount: number;
  lastUpdated: string; // ISO Date string
  weekId: string; // Format: "YYYY-Www"
  monthId: string; // Format: "YYYY-MM"
}

const STORAGE_KEY = 'kivun_global_stats';
const EVENT_KEY = 'kivun_stats_updated';

// Helper to get ISO week number
const getWeekId = (date: Date) => {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  const dayNum = d.getUTCDay() || 7;
  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  const weekNo = Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
  return `${d.getUTCFullYear()}-W${weekNo}`;
};

const getMonthId = (date: Date) => {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
};

const getInitialStats = (): GlobalStatsData => {
  const now = new Date();
  return {
    totalCharsAllTime: 0,
    totalCharsMonth: 0,
    totalCharsWeek: 0,
    totalReplacements: 0,
    usageCount: 0,
    lastUpdated: now.toISOString(),
    weekId: getWeekId(now),
    monthId: getMonthId(now),
  };
};

export const statsService = {
  getStats: (): GlobalStatsData => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (!stored) return getInitialStats();
      return JSON.parse(stored);
    } catch (e) {
      return getInitialStats();
    }
  },

  updateStats: (charsCount: number, replacementsCount: number) => {
    const current = statsService.getStats();
    const now = new Date();
    const currentWeekId = getWeekId(now);
    const currentMonthId = getMonthId(now);

    // Logic: Check if we need to reset periodic counters
    if (current.weekId !== currentWeekId) {
      current.totalCharsWeek = 0;
      current.weekId = currentWeekId;
    }

    if (current.monthId !== currentMonthId) {
      current.totalCharsMonth = 0;
      current.monthId = currentMonthId;
    }

    // Update Values
    current.totalCharsAllTime += charsCount;
    current.totalCharsMonth += charsCount;
    current.totalCharsWeek += charsCount;
    current.totalReplacements += replacementsCount;
    current.usageCount += 1;
    current.lastUpdated = now.toISOString();

    // Save
    localStorage.setItem(STORAGE_KEY, JSON.stringify(current));

    // Dispatch event for UI updates
    window.dispatchEvent(new Event(EVENT_KEY));

    return current;
  },

  resetStats: (password: string): boolean => {
    try {
        if (password.trim() === 'amitamit') {
            const empty = getInitialStats();
            localStorage.setItem(STORAGE_KEY, JSON.stringify(empty));
            window.dispatchEvent(new Event(EVENT_KEY));
            return true;
        }
        return false;
    } catch (e) {
        console.error("Failed to reset stats", e);
        return false;
    }
  },

  subscribe: (callback: () => void) => {
    window.addEventListener(EVENT_KEY, callback);
    return () => window.removeEventListener(EVENT_KEY, callback);
  }
};

