            ul, ol {
                margin-top: 0;
                margin-bottom: 0;
                direction: rtl;
                unicode-bidi: embed;
            }

            /* Ensure bullets/numbers stay on the right side */
            li {
                direction: rtl;
                text-align: right;
                margin-right: 24pt; /* Indent for bullet */
                mso-list-l-id: 1; /* Help Word identify lists */
            }

            /* Fix for paragraphs */
            p {
                margin: 0;
                padding: 0;
